solution_code:
#include <iostream>
#include <iomanip>

int main() {
    int n;
    std::cin >> n;

    int sum = 0;
    for (int i = 0; i < n; ++i) {
        int val;
        std::cin >> val;
        sum += val;
    }

    double avg = static_cast<double>(sum) / n;
    std::cout << "Average: " << std::fixed << std::setprecision(2) << avg << '\n';
    return 0;
}

